import{_ as p,C as c,o as a,c as d,a2 as n,b as t,w as e,a as l,E as r,a3 as i}from"./chunks/framework.B72_uj9U.js";const A=JSON.parse('{"title":"Codex CLI — Unique Patterns & Differentiators","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/codex/unique-patterns.md","filePath":"research/agents/codex/unique-patterns.md"}'),y={name:"research/agents/codex/unique-patterns.md"};function u(h,s,m,g,b,C){const o=c("Mermaid");return a(),d("div",null,[s[2]||(s[2]=n(`<h1 id="codex-cli-—-unique-patterns-differentiators" tabindex="-1">Codex CLI — Unique Patterns &amp; Differentiators <a class="header-anchor" href="#codex-cli-—-unique-patterns-differentiators" aria-label="Permalink to &quot;Codex CLI — Unique Patterns &amp; Differentiators&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Codex CLI stands apart from other terminal coding agents through its Rust-native implementation, OS-level sandboxing without containers, the SQ/EQ architecture pattern, and deep integration with OpenAI&#39;s model ecosystem. This document catalogs the patterns that make Codex CLI architecturally distinct.</p><h2 id="_1-os-native-sandboxing-no-containers-no-vms" tabindex="-1">1. OS-Native Sandboxing (No Containers, No VMs) <a class="header-anchor" href="#_1-os-native-sandboxing-no-containers-no-vms" aria-label="Permalink to &quot;1. OS-Native Sandboxing (No Containers, No VMs)&quot;">​</a></h2><h3 id="the-key-differentiator" tabindex="-1">The Key Differentiator <a class="header-anchor" href="#the-key-differentiator" aria-label="Permalink to &quot;The Key Differentiator&quot;">​</a></h3><p>While Claude Code relies on <strong>no sandboxing by default</strong> (trusting the user to run in a safe environment) and other agents use Docker containers, Codex CLI implements <strong>OS-native sandboxing</strong> that requires zero additional infrastructure:</p><table tabindex="0"><thead><tr><th>Agent</th><th>Sandbox Approach</th></tr></thead><tbody><tr><td><strong>Codex CLI</strong></td><td>OS-native: Seatbelt (macOS), bubblewrap+seccomp (Linux), ACLs+Firewall (Windows)</td></tr><tr><td><strong>Claude Code</strong></td><td>No sandbox by default; user-managed Docker optional</td></tr><tr><td><strong>Aider</strong></td><td>No sandbox; git-based safety net</td></tr><tr><td><strong>Cline</strong></td><td>VS Code extension sandbox only</td></tr><tr><td><strong>Cursor Agent</strong></td><td>Editor-level sandbox</td></tr></tbody></table><h3 id="three-layer-linux-security" tabindex="-1">Three-Layer Linux Security <a class="header-anchor" href="#three-layer-linux-security" aria-label="Permalink to &quot;Three-Layer Linux Security&quot;">​</a></h3><p>Codex&#39;s Linux sandbox is the most sophisticated in the open-source agent space:</p><p><strong>Layer 1 — Bubblewrap (mount namespace isolation)</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>--ro-bind / /              # Entire filesystem read-only</span></span>
<span class="line"><span>--bind $PWD $PWD           # Only workspace writable</span></span>
<span class="line"><span>--ro-bind .git .git        # Git dir always protected</span></span>
<span class="line"><span>--unshare-user             # User namespace isolation</span></span>
<span class="line"><span>--unshare-pid              # PID namespace isolation</span></span>
<span class="line"><span>--unshare-net              # Network namespace isolation</span></span></code></pre></div><p><strong>Layer 2 — seccomp (syscall filtering)</strong></p><ul><li>Blocks <code>ptrace</code>, <code>io_uring_*</code> (async I/O bypass), all network syscalls</li><li>Socket creation limited to <code>AF_UNIX</code> only</li><li><code>PR_SET_NO_NEW_PRIVS</code> prevents privilege escalation</li></ul><p><strong>Layer 3 — Process hardening (pre-main)</strong></p><ul><li><code>#[ctor::ctor]</code> runs before <code>main()</code></li><li>Disables core dumps (<code>RLIMIT_CORE=0</code>)</li><li>Blocks debugger attachment (<code>PT_DENY_ATTACH</code> on macOS, <code>PR_SET_DUMPABLE=0</code> on Linux)</li><li>Strips <code>LD_*</code>/<code>DYLD_*</code> environment variables (prevents shared-library injection)</li></ul><h3 id="windows-sandbox-innovation" tabindex="-1">Windows Sandbox Innovation <a class="header-anchor" href="#windows-sandbox-innovation" aria-label="Permalink to &quot;Windows Sandbox Innovation&quot;">​</a></h3><p>The Windows implementation is entirely unique in the agent space — no other coding agent has a Windows-native sandbox:</p><ol><li>Creates dedicated <strong>sandbox user accounts</strong></li><li>Applies <strong>Windows ACL Deny ACEs</strong> for filesystem restriction</li><li>Creates <strong>per-SID Windows Firewall rules</strong> for network blocking</li><li>Runs on an <strong>alternate desktop</strong> for visual + message isolation</li><li>Uses <strong>restricted security tokens</strong> for process creation</li><li><strong>DPAPI protection</strong> for credential storage</li></ol><h3 id="vendored-bubblewrap" tabindex="-1">Vendored Bubblewrap <a class="header-anchor" href="#vendored-bubblewrap" aria-label="Permalink to &quot;Vendored Bubblewrap&quot;">​</a></h3><p>Codex ships a <strong>vendored bubblewrap binary</strong> as a fallback when the system <code>/usr/bin/bwrap</code> isn&#39;t available. This means sandbox protection works on any Linux system without additional package installation.</p><h2 id="_2-sq-eq-architecture-vs-direct-function-calls" tabindex="-1">2. SQ/EQ Architecture (vs. Direct Function Calls) <a class="header-anchor" href="#_2-sq-eq-architecture-vs-direct-function-calls" aria-label="Permalink to &quot;2. SQ/EQ Architecture (vs. Direct Function Calls)&quot;">​</a></h2><h3 id="the-pattern" tabindex="-1">The Pattern <a class="header-anchor" href="#the-pattern" aria-label="Permalink to &quot;The Pattern&quot;">​</a></h3><p>Most agents use direct function calls between UI and core logic. Codex uses a formal <strong>Submission Queue / Event Queue</strong> message-passing pattern:</p>`,23)),(a(),t(i,null,{default:e(()=>[r(o,{id:"mermaid-180",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20A%5B%22UI%0A(TUI%2C%20exec%2C%20app-srv)%22%5D%0A%20%20%20%20B%5B%22Core%0A(Session%2C%20Agent)%22%5D%0A%0A%20%20%20%20A%20--%3E%7C%22SQ%20(Op%20variants)%22%7C%20B%0A%20%20%20%20B%20--%3E%7C%22EQ%20(EventMsg%20variants)%22%7C%20A%0A"})]),fallback:e(()=>[...s[0]||(s[0]=[l(" Loading... ",-1)])]),_:1})),s[3]||(s[3]=n(`<h3 id="why-this-matters" tabindex="-1">Why This Matters <a class="header-anchor" href="#why-this-matters" aria-label="Permalink to &quot;Why This Matters&quot;">​</a></h3><ol><li><strong>Multiple frontends</strong>: TUI, <code>codex exec</code>, IDE extension (app-server), and MCP server all share the same core — just different SQ/EQ consumers</li><li><strong>Async decoupling</strong>: UI never blocks on model calls or tool execution</li><li><strong>Testability</strong>: Core can be tested with synthetic SQ inputs and EQ assertions</li><li><strong>Distribution</strong>: The exec-server extends SQ/EQ over JSON-RPC/WebSocket</li><li><strong>Tracing</strong>: W3C trace context propagates through submissions for OTel</li></ol><h3 id="comparison" tabindex="-1">Comparison <a class="header-anchor" href="#comparison" aria-label="Permalink to &quot;Comparison&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Agent</th><th>UI↔Core Communication</th></tr></thead><tbody><tr><td><strong>Codex CLI</strong></td><td>SQ/EQ channels (typed Rust enums)</td></tr><tr><td><strong>Claude Code</strong></td><td>Direct async function calls</td></tr><tr><td><strong>Aider</strong></td><td>Synchronous Python method calls</td></tr><tr><td><strong>Continue</strong></td><td>VS Code extension message passing</td></tr></tbody></table><h2 id="_3-rust-native-implementation" tabindex="-1">3. Rust-Native Implementation <a class="header-anchor" href="#_3-rust-native-implementation" aria-label="Permalink to &quot;3. Rust-Native Implementation&quot;">​</a></h2><h3 id="zero-dependencies-at-runtime" tabindex="-1">Zero Dependencies at Runtime <a class="header-anchor" href="#zero-dependencies-at-runtime" aria-label="Permalink to &quot;Zero Dependencies at Runtime&quot;">​</a></h3><p>Codex CLI ships as a <strong>single static binary</strong> with no runtime dependencies:</p><ul><li>No Node.js, Python, or JVM required</li><li>No Docker daemon needed</li><li>Sandbox primitives are OS-native</li><li>Vendored bubblewrap for Linux</li></ul><h3 id="compile-time-security" tabindex="-1">Compile-Time Security <a class="header-anchor" href="#compile-time-security" aria-label="Permalink to &quot;Compile-Time Security&quot;">​</a></h3><p>Security measures that happen <strong>before <code>main()</code> even runs</strong>:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#F9E2AF;font-style:italic;">#</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">ctor</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">ctor</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> harden_process</span><span style="color:#9399B2;">()</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Runs at process load time, before main()</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    #</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">cfg</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">target_os </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;linux&quot;</span><span style="color:#9399B2;">)]</span></span>
<span class="line"><span style="color:#9399B2;">    {</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">        prctl</span><span style="color:#9399B2;">(</span><span style="color:#FAB387;">PR_SET_DUMPABLE</span><span style="color:#9399B2;">,</span><span style="color:#FAB387;"> 0</span><span style="color:#9399B2;">);</span><span style="color:#6C7086;font-style:italic;">       // No ptrace</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">        setrlimit</span><span style="color:#9399B2;">(</span><span style="color:#FAB387;">RLIMIT_CORE</span><span style="color:#9399B2;">,</span><span style="color:#FAB387;"> 0</span><span style="color:#9399B2;">);</span><span style="color:#6C7086;font-style:italic;">       // No core dumps</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">        remove_ld_env_vars</span><span style="color:#9399B2;">();</span><span style="color:#6C7086;font-style:italic;">             // No LD_PRELOAD</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    #</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">cfg</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">target_os </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;macos&quot;</span><span style="color:#9399B2;">)]</span></span>
<span class="line"><span style="color:#9399B2;">    {</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">        ptrace</span><span style="color:#9399B2;">(</span><span style="color:#FAB387;">PT_DENY_ATTACH</span><span style="color:#9399B2;">);</span><span style="color:#6C7086;font-style:italic;">           // No debugger</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">        setrlimit</span><span style="color:#9399B2;">(</span><span style="color:#FAB387;">RLIMIT_CORE</span><span style="color:#9399B2;">,</span><span style="color:#FAB387;"> 0</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">        remove_dyld_env_vars</span><span style="color:#9399B2;">();</span><span style="color:#6C7086;font-style:italic;">           // No DYLD_INSERT_LIBRARIES</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><h3 id="api-key-security" tabindex="-1">API Key Security <a class="header-anchor" href="#api-key-security" aria-label="Permalink to &quot;API Key Security&quot;">​</a></h3><p>The Responses API proxy (<code>responses-api-proxy</code>) demonstrates extreme care:</p><ul><li>API key read from <strong>stdin</strong> (never environment variables)</li><li>Key memory locked with <strong><code>mlock(2)</code></strong> (never swapped to disk)</li><li>Key leaked to <code>&#39;static</code> lifetime via <code>.leak()</code> for <code>HeaderValue::from_static()</code></li><li>Header marked as <strong><code>.set_sensitive(true)</code></strong> (excluded from debug output)</li><li>Only <code>POST /v1/responses</code> forwarded — no other endpoints exposed</li></ul><h2 id="_4-multi-model-support-with-provider-abstraction" tabindex="-1">4. Multi-Model Support with Provider Abstraction <a class="header-anchor" href="#_4-multi-model-support-with-provider-abstraction" aria-label="Permalink to &quot;4. Multi-Model Support with Provider Abstraction&quot;">​</a></h2><h3 id="built-in-providers" tabindex="-1">Built-in Providers <a class="header-anchor" href="#built-in-providers" aria-label="Permalink to &quot;Built-in Providers&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Provider</th><th>Default URL</th><th>Auth</th></tr></thead><tbody><tr><td><code>openai</code></td><td><code>api.openai.com/v1</code></td><td>OAuth / API key</td></tr><tr><td><code>ollama</code></td><td><code>localhost:11434/v1</code></td><td>None</td></tr><tr><td><code>lmstudio</code></td><td><code>localhost:1234/v1</code></td><td>None</td></tr></tbody></table><h3 id="custom-provider-configuration" tabindex="-1">Custom Provider Configuration <a class="header-anchor" href="#custom-provider-configuration" aria-label="Permalink to &quot;Custom Provider Configuration&quot;">​</a></h3><div class="language-toml"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">[</span><span style="color:#CDD6F4;">model_providers.my_provider</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">base_url </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;https://my-api.example.com/v1&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">env_key </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;MY_API_KEY&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">wire_api </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;responses&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">request_max_retries </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> 4</span></span>
<span class="line"><span style="color:#CDD6F4;">stream_max_retries </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> 5</span></span>
<span class="line"><span style="color:#CDD6F4;">stream_idle_timeout_ms </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> 300000</span></span></code></pre></div><h3 id="openai-model-lineup" tabindex="-1">OpenAI Model Lineup <a class="header-anchor" href="#openai-model-lineup" aria-label="Permalink to &quot;OpenAI Model Lineup&quot;">​</a></h3><p>The recommended models for Codex CLI:</p><ul><li><strong>GPT-5.4</strong> — Recommended default (frontier coding + reasoning)</li><li><strong>GPT-5.3-Codex</strong> — Specialized coding model</li><li><strong>GPT-5.3-Codex-Spark</strong> — Fast mode (Pro subscribers only)</li><li><strong>GPT-5.2-Codex</strong> — Previous generation</li><li>Legacy: <code>codex-mini-latest</code>, <code>o4-mini</code>, etc.</li></ul><h3 id="responses-api-only" tabindex="-1">Responses API Only <a class="header-anchor" href="#responses-api-only" aria-label="Permalink to &quot;Responses API Only&quot;">​</a></h3><p>Codex has <strong>dropped Chat Completions entirely</strong> — only the Responses API wire format is supported. Attempting <code>wire_api = &quot;chat&quot;</code> produces an error with migration instructions. This is a bold commitment to the newer API.</p><h2 id="_5-execution-policy-system" tabindex="-1">5. Execution Policy System <a class="header-anchor" href="#_5-execution-policy-system" aria-label="Permalink to &quot;5. Execution Policy System&quot;">​</a></h2><h3 id="two-generation-policy-engine" tabindex="-1">Two-Generation Policy Engine <a class="header-anchor" href="#two-generation-policy-engine" aria-label="Permalink to &quot;Two-Generation Policy Engine&quot;">​</a></h3><p>Codex maintains both a new and legacy policy system:</p><p><strong>New Engine</strong> — Prefix-rule matching with three-valued decisions:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">enum</span><span style="color:#F9E2AF;font-style:italic;"> Decision</span><span style="color:#9399B2;"> {</span><span style="color:#F9E2AF;font-style:italic;"> Allow</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> Prompt</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> Forbidden</span><span style="color:#9399B2;"> }</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">// Policy stored as:</span></span>
<span class="line"><span style="color:#CDD6F4;">rules_by_program</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> MultiMap</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">String</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> RuleRef</span><span style="color:#89DCEB;">&gt;</span><span style="color:#6C7086;font-style:italic;">  // cmd → rules</span></span>
<span class="line"><span style="color:#CDD6F4;">network_rules</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Vec</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">NetworkRule</span><span style="color:#89DCEB;">&gt;</span><span style="color:#6C7086;font-style:italic;">               // domain → decision</span></span></code></pre></div><p><strong>Legacy Engine</strong> — Python-like DSL with typed argument matching:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>program ls:</span></span>
<span class="line"><span>    flags: -1 -a -l</span></span>
<span class="line"><span>    args: ARG_RFILES_OR_CWD</span></span>
<span class="line"><span></span></span>
<span class="line"><span>program sed:</span></span>
<span class="line"><span>    args: ARG_SED_COMMAND ARG_RFILES</span></span>
<span class="line"><span>    # Blocks &#39;e&#39; flag which would execute shell commands</span></span></code></pre></div><p>The <strong>84KB shell command parser</strong> (<code>parse_command.rs</code>) is the largest single file in the codebase — it decomposes complex shell expressions (pipes, redirections, subshells, command substitutions) into individual executable invocations for policy evaluation.</p><h3 id="dynamic-policy-amendment" tabindex="-1">Dynamic Policy Amendment <a class="header-anchor" href="#dynamic-policy-amendment" aria-label="Permalink to &quot;Dynamic Policy Amendment&quot;">​</a></h3><p>When users approve a command, they can optionally add an <strong>execution policy amendment</strong> that auto-approves similar commands in the future:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#F9E2AF;font-style:italic;">ExecApprovalRequestEvent</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">    proposed_execpolicy_amendment</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Option</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">ExecPolicyAmendment</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    proposed_network_policy_amendments</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Option</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">Vec</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">NetworkPolicyAmendment</span><span style="color:#89DCEB;">&gt;&gt;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><h2 id="_6-enterprise-grade-configuration" tabindex="-1">6. Enterprise-Grade Configuration <a class="header-anchor" href="#_6-enterprise-grade-configuration" aria-label="Permalink to &quot;6. Enterprise-Grade Configuration&quot;">​</a></h2><h3 id="layered-config-with-mdm-support" tabindex="-1">Layered Config with MDM Support <a class="header-anchor" href="#layered-config-with-mdm-support" aria-label="Permalink to &quot;Layered Config with MDM Support&quot;">​</a></h3>`,37)),(a(),t(i,null,{default:e(()=>[r(o,{id:"mermaid-463",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20A%5B%22MDM%20(lowest)%22%5D%20--%3E%20B%5B%22System%22%5D%20--%3E%20C%5B%22User%22%5D%20--%3E%20D%5B%22Project%22%5D%20--%3E%20E%5B%22SessionFlags%20(highest)%22%5D%0A"})]),fallback:e(()=>[...s[1]||(s[1]=[l(" Loading... ",-1)])]),_:1})),s[4]||(s[4]=n(`<p>Enterprise administrators can enforce constraints via MDM (Mobile Device Management) or system-level requirements:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">pub</span><span style="color:#CBA6F7;"> struct</span><span style="color:#F9E2AF;font-style:italic;"> ConfigRequirements</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CDD6F4;"> approval_policy</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Option</span><span style="color:#89DCEB;">&lt;</span><span style="color:#94E2D5;">...</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CDD6F4;"> sandbox_policy</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Option</span><span style="color:#89DCEB;">&lt;</span><span style="color:#94E2D5;">...</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CDD6F4;"> web_search_mode</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Option</span><span style="color:#89DCEB;">&lt;</span><span style="color:#94E2D5;">...</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CDD6F4;"> mcp_servers</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Vec</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">McpServerRequirement</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CDD6F4;"> exec_policy</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Option</span><span style="color:#89DCEB;">&lt;</span><span style="color:#94E2D5;">...</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CDD6F4;"> enforce_residency</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Option</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">ResidencyRequirement</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CDD6F4;"> network</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Option</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">NetworkConstraints</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><h3 id="custom-ca-certificates" tabindex="-1">Custom CA Certificates <a class="header-anchor" href="#custom-ca-certificates" aria-label="Permalink to &quot;Custom CA Certificates&quot;">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">export</span><span style="color:#CDD6F4;"> CODEX_CA_CERTIFICATE</span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;">/path/to/ca-bundle.pem</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Falls back to SSL_CERT_FILE, then system roots</span></span></code></pre></div><p>Enterprise proxies that intercept TLS are fully supported.</p><h3 id="opentelemetry-auditing" tabindex="-1">OpenTelemetry Auditing <a class="header-anchor" href="#opentelemetry-auditing" aria-label="Permalink to &quot;OpenTelemetry Auditing&quot;">​</a></h3><div class="language-toml"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">[</span><span style="color:#CDD6F4;">otel</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">environment </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;staging&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">exporter </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> otlp-http </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">    endpoint </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;https://otel.example.com/v1/logs&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    headers </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> &quot;x-otlp-api-key&quot; </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;\${OTLP_TOKEN}&quot;</span><span style="color:#9399B2;"> }</span></span>
<span class="line"><span style="color:#9399B2;">}}</span></span>
<span class="line"><span style="color:#CDD6F4;">log_user_prompt </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> false</span><span style="color:#6C7086;font-style:italic;">  # redact by default</span></span></code></pre></div><p>Events: <code>codex.conversation_starts</code>, <code>codex.api_request</code>, <code>codex.tool_decision</code>, <code>codex.tool_result</code> with corresponding metrics.</p><h2 id="_7-sub-agent-system" tabindex="-1">7. Sub-Agent System <a class="header-anchor" href="#_7-sub-agent-system" aria-label="Permalink to &quot;7. Sub-Agent System&quot;">​</a></h2><h3 id="resource-controlled-multi-agent" tabindex="-1">Resource-Controlled Multi-Agent <a class="header-anchor" href="#resource-controlled-multi-agent" aria-label="Permalink to &quot;Resource-Controlled Multi-Agent&quot;">​</a></h3><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">pub</span><span style="color:#9399B2;">(</span><span style="color:#CBA6F7;">crate</span><span style="color:#9399B2;">)</span><span style="color:#CBA6F7;"> struct</span><span style="color:#F9E2AF;font-style:italic;"> Guards</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">    active_agents</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Mutex</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">ActiveAgents</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    total_count</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> AtomicUsize</span><span style="color:#9399B2;">,</span><span style="color:#6C7086;font-style:italic;">  // CAS-based max enforcement</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>Sub-agents:</p><ul><li>Have their own context, model calls, and tool execution</li><li>Share the parent&#39;s sandbox manager (enforced by same OS mechanisms)</li><li>Can be spawned with different roles (<code>explorer</code>, <code>worker</code>)</li><li>Support session resume from persisted rollout files</li><li>Are resource-limited via atomic counter guards</li></ul><h3 id="role-based-agent-configuration" tabindex="-1">Role-Based Agent Configuration <a class="header-anchor" href="#role-based-agent-configuration" aria-label="Permalink to &quot;Role-Based Agent Configuration&quot;">​</a></h3><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">// Built-in roles</span></span>
<span class="line"><span style="color:#A6E3A1;">&quot;explorer&quot;</span><span style="color:#CDD6F4;"> → codebase </span><span style="color:#F9E2AF;font-style:italic;">Q</span><span style="color:#94E2D5;">&amp;</span><span style="color:#F9E2AF;font-style:italic;">A</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> may </span><span style="color:#CBA6F7;">use</span><span style="color:#CDD6F4;"> faster model</span></span>
<span class="line"><span style="color:#CDD6F4;">&quot;worker&quot;   → execution tasks</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> file ownership semantics</span></span>
<span class="line"><span style="color:#CDD6F4;">&quot;default&quot;  → standard agent behavior</span></span></code></pre></div><p>Custom roles can be defined in config with per-role model, reasoning effort, and developer instructions.</p><h2 id="_8-session-persistence-resume" tabindex="-1">8. Session Persistence &amp; Resume <a class="header-anchor" href="#_8-session-persistence-resume" aria-label="Permalink to &quot;8. Session Persistence &amp; Resume&quot;">​</a></h2><h3 id="jsonl-rollout-files" tabindex="-1">JSONL Rollout Files <a class="header-anchor" href="#jsonl-rollout-files" aria-label="Permalink to &quot;JSONL Rollout Files&quot;">​</a></h3><p>Every session is persisted as JSONL rollout files under <code>~/.codex/sessions/</code>. Each line is a serialized <code>ResponseItem</code> or <code>Op</code> that can be replayed:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#89B4FA;font-style:italic;">codex</span><span style="color:#A6E3A1;"> resume</span><span style="color:#6C7086;font-style:italic;">              # Interactive picker</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">codex</span><span style="color:#A6E3A1;"> resume</span><span style="color:#A6E3A1;"> --last</span><span style="color:#6C7086;font-style:italic;">       # Most recent session</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">codex</span><span style="color:#A6E3A1;"> resume</span><span style="color:#94E2D5;"> &lt;</span><span style="color:#A6E3A1;">SESSION_I</span><span style="color:#CDD6F4;">D</span><span style="color:#94E2D5;">&gt;</span><span style="color:#6C7086;font-style:italic;"> # Specific session</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">codex</span><span style="color:#A6E3A1;"> exec</span><span style="color:#A6E3A1;"> resume</span><span style="color:#A6E3A1;"> --last</span><span style="color:#A6E3A1;"> &quot;Fix the issues&quot;</span><span style="color:#6C7086;font-style:italic;">  # Non-interactive resume</span></span></code></pre></div><p>Sub-agent rollouts are stored alongside parent rollouts and recursively resumed.</p><h3 id="sqlite-state-database" tabindex="-1">SQLite State Database <a class="header-anchor" href="#sqlite-state-database" aria-label="Permalink to &quot;SQLite State Database&quot;">​</a></h3><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">pub</span><span style="color:#CBA6F7;"> const</span><span style="color:#FAB387;"> STATE_DB_VERSION</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> i32</span><span style="color:#94E2D5;"> =</span><span style="color:#FAB387;"> 5</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#CBA6F7;">pub</span><span style="color:#CBA6F7;"> const</span><span style="color:#FAB387;"> LOGS_DB_VERSION</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> i32</span><span style="color:#94E2D5;"> =</span><span style="color:#FAB387;"> 1</span><span style="color:#9399B2;">;</span></span></code></pre></div><p>Stores thread metadata, agent job state, and structured logs. Versioned schema for forward compatibility.</p><h2 id="_9-web-search-with-safety-controls" tabindex="-1">9. Web Search with Safety Controls <a class="header-anchor" href="#_9-web-search-with-safety-controls" aria-label="Permalink to &quot;9. Web Search with Safety Controls&quot;">​</a></h2><p>Three modes with escalating risk:</p><table tabindex="0"><thead><tr><th>Mode</th><th>Behavior</th><th>Risk</th></tr></thead><tbody><tr><td><code>cached</code> (default)</td><td>Pre-indexed OpenAI cache</td><td>Low (no live fetch)</td></tr><tr><td><code>live</code></td><td>Real-time web browsing</td><td>Higher (prompt injection risk)</td></tr><tr><td><code>disabled</code></td><td>No web search</td><td>None</td></tr></tbody></table><p>The cached mode is a unique safety feature — web results come from an OpenAI-maintained index rather than live pages, reducing prompt injection surface area.</p><h2 id="_10-managed-network-proxy" tabindex="-1">10. Managed Network Proxy <a class="header-anchor" href="#_10-managed-network-proxy" aria-label="Permalink to &quot;10. Managed Network Proxy&quot;">​</a></h2><p>For environments that need controlled network access (not just allow/deny), Codex implements a <strong>proxy bridge</strong>:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Sandboxed Process (isolated network namespace)</span></span>
<span class="line"><span>  └── AF_INET → 127.0.0.1:PORT (TCP bridge)</span></span>
<span class="line"><span>       └── UDS socket → parent namespace</span></span>
<span class="line"><span>            └── TCP to configured proxy endpoint</span></span></code></pre></div><p>After the bridge is established, seccomp blocks new <code>AF_UNIX</code>/<code>socketpair</code> creation, preventing bypass. This allows fine-grained network control per domain through the execution policy.</p><h2 id="summary-what-makes-codex-cli-unique" tabindex="-1">Summary: What Makes Codex CLI Unique <a class="header-anchor" href="#summary-what-makes-codex-cli-unique" aria-label="Permalink to &quot;Summary: What Makes Codex CLI Unique&quot;">​</a></h2><ol><li><strong>OS-native sandboxing</strong> — No containers/VMs needed; works on bare metal</li><li><strong>SQ/EQ architecture</strong> — Clean separation enables multiple frontends</li><li><strong>Rust single binary</strong> — Zero runtime dependencies</li><li><strong>Pre-main hardening</strong> — Security before code executes</li><li><strong>Windows-native sandbox</strong> — Only agent with real Windows sandboxing</li><li><strong>Execution policy DSL</strong> — Fine-grained command allowlisting</li><li><strong>Enterprise MDM support</strong> — Corporate-managed security requirements</li><li><strong>Cached web search</strong> — Reduced prompt injection via pre-indexed results</li><li><strong>API key mlock</strong> — Key never touches disk or environment</li><li><strong>Responses API only</strong> — Committed to OpenAI&#39;s modern API format</li></ol>`,34))])}const D=p(y,[["render",u]]);export{A as __pageData,D as default};
